#include<bits/stdc++.h>
using namespace std;

int main()
{
    long long n,m,k;
    scanf("%lld%lld%lld",&n,&m,&k);
    for(long long i=1;i<=k;i++)
    {
        long long x=i,ans=0;
        for(long long j=1;j<m;j++)
        {
            printf("%lld ",x%n+1);
            ans+=x%n+1;
            x/=n;
        }
        printf("%lld\n",ans%n+1);
    }
    return 0;
}
